import{_ as e,o,c as l,a5 as a}from"./chunks/framework.B5tqjWbr.js";const h=JSON.parse('{"title":"UPS 30 天训练计划（30-Day Training Plan）","description":"","frontmatter":{"date":"2026-06-20T00:00:00.000Z","category":"电源控制","source":"power","visibility":"public","title":"UPS 30 天训练计划（30-Day Training Plan）","tags":["power-electronics"],"status":"learning","summary":"每天至少产出下面四类内容中的一种，不能只“看资料”："},"headers":[],"relativePath":"content/power/roadmap/30-day-plan.md","filePath":"content/power/roadmap/30-day-plan.md","lastUpdated":null}'),n={name:"content/power/roadmap/30-day-plan.md"};function t(r,i,c,s,d,p){return o(),l("div",null,[...i[0]||(i[0]=[a('<h1 id="ups-30-天训练计划-30-day-training-plan" tabindex="-1">UPS 30 天训练计划（30-Day Training Plan） <a class="header-anchor" href="#ups-30-天训练计划-30-day-training-plan" aria-label="Permalink to &quot;UPS 30 天训练计划（30-Day Training Plan）&quot;">​</a></h1><h2 id="使用规则-training-rule" tabindex="-1">使用规则（Training Rule） <a class="header-anchor" href="#使用规则-training-rule" aria-label="Permalink to &quot;使用规则（Training Rule）&quot;">​</a></h2><p>每天至少产出下面四类内容中的一种，不能只“看资料”：</p><ul><li>一份概念解释（concept explanation）：必须按“定义、为什么需要、物理直觉、数学形式、仿真观察、固件落地、常见误解”七段式写。</li><li>一个 Python 或 MATLAB/Simulink 仿真产物（simulation artifact）：脚本、模型、波形图或参数记录。</li><li>一份调试记录（debug record）：记录失败现象、猜想、验证过程和结论。</li><li>一个导师问题（mentor question）：必须来自具体仿真、代码或概念卡点。</li></ul><h2 id="第-1-周-基础补齐与-boost-入门-foundation-and-boost" tabindex="-1">第 1 周：基础补齐与 Boost 入门（Foundation and Boost） <a class="header-anchor" href="#第-1-周-基础补齐与-boost-入门-foundation-and-boost" aria-label="Permalink to &quot;第 1 周：基础补齐与 Boost 入门（Foundation and Boost）&quot;">​</a></h2><p>目标：重建 UPS 控制工作所需的最低电路、电力电子和控制基础。</p><p>主题：</p><ul><li>基尔霍夫电流定律（Kirchhoff&#39;s Current Law / KCL）、基尔霍夫电压定律（Kirchhoff&#39;s Voltage Law / KVL）。</li><li>电容电流（capacitor current）、电感电压（inductor voltage）。</li><li>降压变换器（Buck converter）和升压变换器（Boost converter）的开关状态。</li><li>连续导通模式（continuous conduction mode / CCM）、断续导通模式（discontinuous conduction mode / DCM）。</li><li>占空比（duty cycle / D）、电流纹波（current ripple）、电压纹波（voltage ripple）。</li><li>脉宽调制（pulse-width modulation / PWM）、采样（sampling）、离散比例积分控制器（discrete proportional-integral controller / discrete PI）。</li></ul><p>产物：</p><ul><li><code>concepts/power-electronics/boost-converter.md</code></li><li><code>simulations/python/boost_open_loop.py</code></li><li><code>projects/01-boost-basics/README.md</code></li></ul><h2 id="第-2-周-控制核心-control-core" tabindex="-1">第 2 周：控制核心（Control Core） <a class="header-anchor" href="#第-2-周-控制核心-control-core" aria-label="Permalink to &quot;第 2 周：控制核心（Control Core）&quot;">​</a></h2><p>目标：把已有电机控制经验迁移到 UPS 控制。</p><p>主题：</p><ul><li>单相功率因数校正（single-phase power factor correction / single-phase PFC）。</li><li>锁相环（phase-locked loop / PLL）与电网同步（grid synchronization）。</li><li>单相逆变器（single-phase inverter）和 LC 滤波器（LC filter）。</li><li>比例积分控制器（proportional-integral controller / PI）。</li><li>比例谐振控制器（proportional-resonant controller / PR）。</li><li>前馈（feedforward）和采样延迟（sampling delay）。</li></ul><p>产物：</p><ul><li>PFC 概念文档。</li><li>PLL 仿真。</li><li>单相逆变器项目大纲。</li></ul><h2 id="第-3-周-ups-系统-ups-system" tabindex="-1">第 3 周：UPS 系统（UPS System） <a class="header-anchor" href="#第-3-周-ups-系统-ups-system" aria-label="Permalink to &quot;第 3 周：UPS 系统（UPS System）&quot;">​</a></h2><p>目标：理解整机能量流、状态切换、保护、电池路径和旁路。</p><p>主题：</p><ul><li>在线式 UPS 双变换架构（online UPS double-conversion architecture）。</li><li>直流母线协调（DC bus coordination）。</li><li>电池（battery）与双向 DC-DC 变换器（bidirectional DC-DC converter）。</li><li>LLC 谐振变换器（inductor-inductor-capacitor resonant converter / LLC）的能量传递直觉和频率控制边界。</li><li>旁路（bypass）和故障状态机（fault state machine）。</li></ul><p>产物：</p><ul><li>UPS 状态机 Python 脚本。</li><li>故障处理调试记录。</li></ul><h2 id="第-4-周-嵌入式工程化-embedded-engineering" tabindex="-1">第 4 周：嵌入式工程化（Embedded Engineering） <a class="header-anchor" href="#第-4-周-嵌入式工程化-embedded-engineering" aria-label="Permalink to &quot;第 4 周：嵌入式工程化（Embedded Engineering）&quot;">​</a></h2><p>目标：把控制算法连接到真实固件架构。</p><p>主题：</p><ul><li>控制中断服务程序（control interrupt service routine / control ISR）。</li><li>模数转换器（analog-to-digital converter / ADC）与 PWM 同步。</li><li>实时操作系统（real-time operating system / RTOS）任务划分。</li><li>参数存储（parameter storage）。</li><li>通信（communication）和日志（logging）。</li><li>C 语言工程代码阅读（C firmware code reading）：模块边界、控制中断、状态机、保护与通信。</li><li>简化 UPS 软件骨架（simplified UPS firmware skeleton）：启动、采样、控制、保护、故障锁存、通信接口。</li></ul><p>产物：</p><ul><li>固件控制骨架（firmware control skeleton）。</li><li>经导师确认的模块阅读计划。</li></ul><h2 id="后续专题-高功率-ups-拓扑-advanced-ups-topologies" tabindex="-1">后续专题：高功率 UPS 拓扑（Advanced UPS Topologies） <a class="header-anchor" href="#后续专题-高功率-ups-拓扑-advanced-ups-topologies" aria-label="Permalink to &quot;后续专题：高功率 UPS 拓扑（Advanced UPS Topologies）&quot;">​</a></h2><p>这些内容不抢第 1 周 Boost 基础的节奏，但必须进入训练体系：</p><ul><li>维也纳整流器（Vienna rectifier）：三相功率因数校正、高压母线、中点电压平衡。</li><li>三电平逆变器（three-level inverter）：中点钳位、开关状态、调制、母线中点平衡。</li><li>LLC 谐振变换器（inductor-inductor-capacitor resonant converter / LLC）：谐振腔、频率调制、软开关、轻载控制。</li><li>工程代码专题：从 Python/Simulink 现象迁移到 C 语言控制中断、驱动接口、保护状态机和通信协议。</li></ul>',31)])])}const m=e(n,[["render",t]]);export{h as __pageData,m as default};
